-- Seed data for flight-provider mock. INSERT IGNORE => idempotent on restart.




-- ===== Bổ sung: 3 sân bay + 200 chuyến bay rải 01/06–31/08/2026 (ids 31..230) =====





-- ====== Hop nhat ve 1 hang duy nhat: Vietnam Airlines (VN) ======
-- An toan cho DB da co du lieu cu (INSERT IGNORE khong sua hang san co): chuan hoa lai ve VN.
-- Idempotent: sau lan dau khong con VJ nen cac lenh duoi khong tac dong gi them.
UPDATE flights SET flight_number = CONCAT('VN', SUBSTRING(flight_number, 3)) WHERE flight_number LIKE 'VJ%';
UPDATE flights SET airline_code = 'VN' WHERE airline_code = 'VJ';
DELETE FROM airlines WHERE code = 'VJ';

